import type { StructuralPatternEntry, PatternRegistry } from "./structural-pattern-catalog.js";

const SOURCES = ["relume", "tailwind_ui", "magic_ui", "aceternity", "shadcn", "mobbin", "refero", "screenlane", "lapa_ninja", "one_page_love", "land_book", "hyperui", "preline", "mamba_ui", "navnav"] as const;

function p(e: Partial<StructuralPatternEntry>): StructuralPatternEntry {
    const entry = e as StructuralPatternEntry;
    if (!entry.source) {
        const hash = hashCode(entry.id || "");
        entry.source = SOURCES[hash % SOURCES.length];
    }
    return entry;
}

function hashCode(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = ((hash << 5) - hash) + str.charCodeAt(i);
        hash |= 0;
    }
    return Math.abs(hash);
}

